SELECT count(*) FROM keyword, movie_keyword, title, movie_companies, company_type, company_name, movie_info, cast_info WHERE movie_keyword.keyword_id = keyword.id AND movie_keyword.movie_id = title.id AND movie_companies.movie_id = title.id AND movie_companies.company_type_id = company_type.id AND movie_companies.company_id = company_name.id AND movie_info.movie_id = title.id AND cast_info.movie_id = title.id;